phase1.code:
// ---- Data class ----
// Automatically generates: toString, equals, hashCode, copy

data class User(
    val id: Int,
    val name: String,
    val email: String
)

// ---- Regular class for comparison ----
class RegularUser(
    val id: Int,
    val name: String,
    val email: String
)

// ---- Data class with default values ----
data class Product(
    val id: Int,
    val name: String,
    val price: Double = 0.0,
    val category: String = "General"
)

// ---- Data class with methods ----
data class Person(
    val firstName: String,
    val lastName: String,
    val age: Int
) {
    val fullName: String
        get() = "$firstName $lastName"

    fun introduce() = println("Hi, I'm $fullName ($age)")
}

// ---- Data class with complex properties ----
data class Address(
    val street: String,
    val city: String,
    val zipCode: String
)

data class Customer(
    val id: Int,
    val name: String,
    val address: Address
)

fun main() {
    // ---- Creation ----
    val user1 = User(1, "Alice", "alice@example.com")
    val user2 = User(2, "Bob", "bob@example.com")

    // ---- toString (auto-generated) ----
    println("User1: $user1")
    println("User2: $user2")

    // ---- equals (value-based) ----
    val user1Copy = User(1, "Alice", "alice@example.com")
    println("user1 == user1Copy: ${user1 == user1Copy}")  // true

    val regularUser1 = RegularUser(1, "Alice", "alice@example.com")
    val regularUser2 = RegularUser(1, "Alice", "alice@example.com")
    println("regularUser1 == regularUser2: ${regularUser1 == regularUser2}")  // false

    // ---- copy (creates a new instance with modified fields) ----
    val user3 = user1.copy(id = 3, name = "Charlie")
    println("Copied user: $user3")

    // ---- Destructuring ----
    val (id, name, email) = user1
    println("Destructured: id=$id, name=$name, email=$email")

    // ---- Data class with defaults ----
    val product1 = Product(1, "Laptop", 999.99, "Electronics")
    val product2 = Product(2, "Book")
    println("Product1: $product1")
    println("Product2: $product2")

    // ---- Data class with methods ----
    val person = Person("John", "Doe", 30)
    person.introduce()

    // ---- Nested data classes ----
    val address = Address("123 Main St", "New York", "10001")
    val customer = Customer(1, "Alice", address)
    println("Customer: $customer")
    println("City: ${customer.address.city}")

    // ---- Using copy with nested data class ----
    val updatedCustomer = customer.copy(
        address = address.copy(city = "Los Angeles")
    )
    println("Updated: $updatedCustomer")
}

